def remove_thinking(text: str) -> str:
    import re
    text = str(text or "")
    for pattern in [
        r"<think\b[^>]*>[\s\S]*?</think>",
        "<\\u601d\\u8003\\b[^>]*>[\\s\\S]*?</\\u601d\\u8003>",
        r"```(?:thinking|think|\u601d\u8003)[\s\S]*?```",
    ]:
        text = re.sub(pattern, "", text, flags=re.I)
    return text


def clean_lines(text: str) -> str:
    import re
    internal_patterns = [
        "^\\s*\\u6211\\u4eec\\u9700\\u8981.*$",
        "^\\s*\\u6211\\u51c6\\u5907.*$",
        "^\\s*\\u5148.*\\u68b3\\u7406.*$",
        r"^\s*We need to.*$",
        r"^\s*I need to.*$",
        r"^\s*I will.*$",
    ]
    for pattern in internal_patterns:
        text = re.sub(pattern, "", text, flags=re.I | re.M)
    text = re.sub(r"\n{3,}", "\n\n", text)
    return text.strip()


def extract_final_report(text: str) -> str:
    import re
    text = remove_thinking(text)
    match = re.search(r"<final_report\b[^>]*>([\s\S]*?)</final_report>", text, flags=re.I)
    if match:
        return clean_lines(match.group(1))
    text = re.sub(r"<report_ir\b[^>]*>[\s\S]*?</report_ir>", "", text, flags=re.I)
    return clean_lines(text)


def main(report: str, export_body: str) -> dict:
    import json
    final = extract_final_report(report)
    download_url = ""
    qa_summary = ""
    success = True
    blocked = False
    try:
        data = json.loads(export_body or "{}")
        download_url = data.get("download_url", "") or ""
        qa_summary = data.get("qa_summary", "") or ""
        success = bool(data.get("success", True))
        blocked = bool(data.get("blocked", False))
    except Exception:
        pass
    if qa_summary:
        final = final + "\n\n---\n\n质检摘要：\n" + qa_summary
    if success and download_url:
        final = final + "\n\n---\n\n[下载分析报告 Word 文件](" + download_url + ")"
    elif blocked:
        final = "本次报告未导出 Word，需人工确认以下问题：\n\n" + (qa_summary or "质检未通过。") + "\n\n---\n\n" + final
    return {"final_report": final, "download_url": download_url}

